public class Swap {
    static int[] arr = {10, 20, 30};

    static void doubleFirst(int[] a) {
        a[0] = a[0] * 2;
    }

    static void replaceRef(int[] a) {
        a = new int[]{99, 99, 99};  // reassigns local parameter only
    }

    public static void main(String[] args) {
        doubleFirst(arr);
        System.out.println(arr[0]);
        replaceRef(arr);
        System.out.println(arr[0]);
    }
}
